{
  "query": "query Menu($category: Category) { menu(filter: { category: $category }, pagination: { limit: 12, offset: 0 }) { products { id name description image category strainType brand { name } potencyThc { formatted } potencyCbd { formatted } variants { option priceRec priceMed specialPriceRec specialPriceMed } } } }",
  "variables": { "category": "FLOWER" }
}

{
  "query": "query Retailers { retailers { id name slug status offerDelivery offerAnyPickup pricingTypes address { line1 city state postalCode } } }",
  "variables": {}
}

{
  "query": "query Specials { specials { id name description type startDate endDate } }",
  "variables": {}
}

{
  "query": "mutation CreateCheckout($orderType: OrderType!, $pricingType: PricingType!) { createCheckout(orderType: $orderType, pricingType: $pricingType) { id orderType pricingType redirectUrl items { id option quantity } } }",
  "variables": { "orderType": "DELIVERY", "pricingType": "RECREATIONAL" }
}

{
  "query": "mutation AddItemToCheckout($checkoutId: ID!, $productId: ID!, $quantity: Int!, $option: String!) { addItem(checkoutId: $checkoutId, productId: $productId, quantity: $quantity, option: $option) { id items { id option quantity product { name } } } }",
  "variables": { "checkoutId": "", "productId": "", "quantity": 1, "option": "3.5g" }
}

{
  "query": "mutation UpdateCheckoutItemQuantity($checkoutId: ID!, $itemId: ID!, $quantity: Int!) { updateQuantity(checkoutId: $checkoutId, itemId: $itemId, quantity: $quantity) { id items { id quantity } } }",
  "variables": { "checkoutId": "", "itemId": "", "quantity": 2 }
}

{
  "query": "mutation RemoveItemFromCheckout($checkoutId: ID!, $itemId: ID!) { removeItem(checkoutId: $checkoutId, itemId: $itemId) { id items { id } } }",
  "variables": { "checkoutId": "", "itemId": "" }
}

{
  "query": "mutation UpdateCheckout($checkoutId: ID!, $orderType: OrderType!, $pricingType: PricingType!) { updateCheckout(checkoutId: $checkoutId, orderType: $orderType, pricingType: $pricingType) { id orderType pricingType } }",
  "variables": { "checkoutId": "", "orderType": "PICKUP", "pricingType": "RECREATIONAL" }
}

{
  "query": "query Checkout($id: ID!) { checkout(id: $id) { id orderType pricingType redirectUrl items { id option quantity product { name } } } }",
  "variables": { "id": "" }
}
